const inputData =
  $('TigerPitch - Receive Inputs').item.json;

let websiteContent = '';
let fetchStatus = '';

try {

  const websiteFetch =
    $('Fetch Company Website').item;

  const raw =
    websiteFetch.json?.data ||
    websiteFetch.json?.body ||
    websiteFetch.json ||
    '';

  const text =
    typeof raw === 'string'
      ? raw
      : JSON.stringify(raw);

  if (text && text.length > 100) {

    websiteContent =
      text.substring(0, 3000);

    fetchStatus = 'website_success';

  } else {

    throw new Error('Empty website content');
  }

} catch (e1) {

  try {

    const searchFetch =
      $('Search Company Fallback').item;

    const raw =
      searchFetch.json?.data ||
      searchFetch.json?.body ||
      searchFetch.json ||
      '';

    const text =
      typeof raw === 'string'
        ? raw
        : JSON.stringify(raw);

    if (text && text.length > 100) {

      websiteContent =
        text.substring(0, 3000);

      fetchStatus = 'search_success';

    } else {

      throw new Error('Empty search content');
    }

  } catch (e2) {

    fetchStatus = 'fallback_knowledge';

    websiteContent =
      `Company: ${inputData.company_name}.
       Industry: ${inputData.industry}.
       Website and search unavailable.
       Use your training knowledge about this company and industry.`;
  }
}

return [
  {
    json: {
      ...inputData,

      website_content: websiteContent,

      fetch_status: fetchStatus,
    }
  }
];

let researchData = {};

try {
  // Anthropic node returns: content[0].text
  const rawText = $input.first().json
    ?.content?.[0]?.text || '{}';

  // Clean any backticks just in case
  let cleaned = rawText
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();

  // Extract between first { and last }
  const firstBrace = cleaned.indexOf('{');
  const lastBrace = cleaned.lastIndexOf('}');

  if (firstBrace !== -1 && lastBrace !== -1) {
    cleaned = cleaned.substring(firstBrace, lastBrace + 1);
    researchData = JSON.parse(cleaned);
  } else {
    throw new Error('No JSON found');
  }

} catch (e) {
  researchData = {
    company_overview: 'Research unavailable',
    products_services: 'Information unavailable',
    company_size: 'Unknown',
    recent_initiatives: 'No recent initiatives identified',
    technology_mentioned: 'No technology information available',
    visible_pain_points: 'Business pain points could not be identified',
    data_source: 'fallback'
  };
}

const webhookData = $('TigerPitch - Receive Inputs').first().json;
const handlerData = $('Website Content Handler').first().json;

return {
  ...webhookData,
  ...handlerData,
  research_data: researchData,
};

let industryData = {};

try {
  // Anthropic node returns: content[0].text
