  }

} catch (e) {
  industryData = {
    industry_trends: 'Industry trends unavailable',
    common_root_causes: 'Root cause analysis unavailable',
    benchmark_data: 'Benchmark data unavailable',
    decision_maker_priorities: 'Decision maker priorities unavailable',
