let solutions = [];
const prev = $('Knowledge Base Lookup').first().json;

try {
  const rawText = $input.first().json
    ?.content?.[0]?.text || '';

  if (!rawText) throw new Error('Empty');

  let cleaned = rawText
    .replace(/[\u0000-\u001F\u007F-\u009F]/g, ' ')
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();

  // Find array or object
  const firstBracket = cleaned.indexOf('[');
  const lastBracket = cleaned.lastIndexOf(']');
  const firstBrace = cleaned.indexOf('{');
  const lastBrace = cleaned.lastIndexOf('}');

  if (firstBracket !== -1 && lastBracket !== -1) {
    // Normal array response
    const jsonStr = cleaned.substring(firstBracket, lastBracket + 1);
    solutions = JSON.parse(jsonStr);
  } else if (firstBrace !== -1 && lastBrace !== -1) {
    // Single object — wrap in array
    const jsonStr = cleaned.substring(firstBrace, lastBrace + 1);
    const parsed = JSON.parse(jsonStr);
    // Check if it has solutions array inside
    if (parsed.solutions && Array.isArray(parsed.solutions)) {
      solutions = parsed.solutions;
    } else {
      solutions = [parsed];
    }
  } else {
    throw new Error('No JSON found');
  }

  // Add option numbers if missing
  solutions = solutions.map((s, i) => ({
    ...s,
    option_number: s.option_number || (i + 1)
  }));

  // Validate we have 3
  if (!Array.isArray(solutions) || solutions.length === 0) {
    throw new Error('Empty solutions');
  }

} catch (e) {
  solutions = [
    {
      option_number: 1,
      title: 'Predictive Analytics Solution',
      description: 'Build a predictive model to identify and address the core business problem proactively.',
      approach: 'Phase 1: Data audit → Phase 2: Model build → Phase 3: Deploy',
      key_deliverables: 'Predictive model, Dashboard, Playbook',
      best_for: 'Organizations with good data infrastructure',
      estimated_effort: 'medium',
      expected_outcome: '20-30% improvement within 3 months'
    },
    {
      option_number: 2,
      title: 'Data Intelligence Platform',
      description: 'Create a unified analytics platform delivering real-time actionable insights.',
      approach: 'Phase 1: Data consolidation → Phase 2: Analytics layer → Phase 3: Training',
      key_deliverables: 'Data platform, Dashboards, Training',
      best_for: 'Organizations needing better data visibility',
      estimated_effort: 'high',
      expected_outcome: 'Unified view of all key business metrics'
    },
    {
      option_number: 3,
      title: 'Quick Win POC',
      description: 'Fast 4-week proof of concept demonstrating immediate measurable value.',
      approach: 'Phase 1: Scoping → Phase 2: Prototype → Phase 3: Roadmap',
      key_deliverables: 'Working prototype, ROI analysis, Roadmap',
      best_for: 'Organizations wanting to validate before full investment',
      estimated_effort: 'low',
      expected_outcome: 'Validated approach with clear ROI projection'
    }
  ];
}

return {
  ...prev,
  solutions: solutions,
  status: 'solutions_ready'
};

let refinedSolution = {};
const prev = $('Knowledge Base Lookup').first().json;

try {
  const rawText = $input.first().json
    ?.content?.[0]?.text || '';

  let cleaned = rawText
    .replace(/[\u0000-\u001F\u007F-\u009F]/g, ' ')
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();

  const firstBrace = cleaned.indexOf('{');
  const lastBrace = cleaned.lastIndexOf('}');

  if (firstBrace !== -1 && lastBrace !== -1) {
    refinedSolution = JSON.parse(
      cleaned.substring(firstBrace, lastBrace + 1)
    );
  } else {
    throw new Error('No JSON found');
  }

} catch(e) {
  refinedSolution = {
    option_number: 1,
    title: 'Custom Solution Approach',
    description: prev.body?.own_solution || 'User defined solution',
    approach: 'Phase 1: Discovery → Phase 2: Build → Phase 3: Deploy',
    key_deliverables: 'Custom solution, Documentation, Training',
    best_for: 'Tailored to specific client needs',
    estimated_effort: 'medium',
    expected_outcome: 'Measurable improvement in identified problem area'
  };
}

const response = {
  status: "own_solution_ready",
  company_name: prev.body?.company_name || prev.company_name || '',
  industry: prev.body?.industry || prev.industry || '',
  decision_maker: prev.body?.decision_maker || prev.decision_maker || '',
  problem_statement: prev.body?.problem_statement || prev.problem_statement || '',
  business_impact: prev.body?.business_impact || prev.business_impact || '',
  technologies: prev.body?.technologies || prev.technologies || [],
  delivery_type: prev.body?.delivery_type || prev.delivery_type || '',
  timeline: prev.body?.timeline || prev.timeline || '',
  budget_range: prev.body?.budget_range || prev.budget_range || '',
  selected_solution: refinedSolution,
  solutions: [refinedSolution],
  research_data: prev.research_data || {},
  industry_data: prev.industry_data || {},
  kb_context: prev.kb_context || '',
  has_kb: prev.has_kb || false
};

return { response: JSON.stringify(response) };

let painMap = {};

try {
  const rawText = $input.first().json
    ?.content?.[0]?.text || '{}';

  let cleaned = rawText
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();

  const firstBrace = cleaned.indexOf('{');
  const lastBrace = cleaned.lastIndexOf('}');

  if (firstBrace !== -1 && lastBrace !== -1) {
    cleaned = cleaned.substring(firstBrace, lastBrace + 1);
    painMap = JSON.parse(cleaned);
  } else {
    throw new Error('No JSON found');
  }

  if (!painMap.pain_points) {
    throw new Error('Invalid pain map structure');
  }

} catch (e) {
  const prev = $('Receive Selected Solution').first().json;

  painMap = {
    pain_points: [
      {
        pain: prev.body?.problem_statement || 'Business challenge identified',
        root_cause: 'Limited visibility into operational and customer intelligence',
        solution_component: prev.body?.selected_solution?.title || 'AI-driven analytics solution',
        expected_outcome: 'Improved decision-making and operational efficiency',
        timeframe: prev.body?.timeline || '3 months'
      }
    ],
    overall_value_statement: 'AI-driven modernization designed to improve business performance.',
    roi_indicator: 'Expected measurable ROI within 6-12 months'
  };
}

const prev = $('Receive Selected Solution').first().json;

return {
  ...prev,
  pain_map: painMap
};

const data = $input.first().json || {};
const rawProposal = data.proposal || {};

// Map all 11 new sections
const p = {
  engagement_title:     rawProposal.engagement_title     || 'AI-Powered Analytics Program',
  situation_assessment: rawProposal.situation_assessment || 'Not available',
  root_cause_diagnosis: rawProposal.root_cause_diagnosis || 'Not available',
  tiger_pov:            rawProposal.tiger_pov            || 'Not available',
  proposed_solution:    rawProposal.proposed_solution    || 'Not available',
  pain_solution_map:    rawProposal.pain_solution_map    || 'Not available',
  tiger_accelerators:   rawProposal.tiger_accelerators   || 'Not available',
  investment_roi:       rawProposal.investment_roi       || 'Not available',
  risk_mitigation:      rawProposal.risk_mitigation      || 'Not available',
  our_team:             rawProposal.our_team             || 'Not available',
  credentials:          rawProposal.credentials          || 'Not available',
  next_steps:           rawProposal.next_steps           || 'Not available',
};

const company      = data.body?.company_name   || data.company_name   || 'Unknown Company';
const decisionMaker= data.body?.decision_maker || data.decision_maker || 'Decision Maker';
const industry     = data.body?.industry       || data.industry       || '';
const budget       = data.body?.budget_range   || data.budget_range   || '';
const timeline     = data.body?.timeline       || data.timeline       || '';
const delivery     = data.body?.delivery_type  || data.delivery_type  || '';
const hasKB        = data.body?.has_kb         || data.has_kb         || false;
const kbIndustry   = data.body?.kb_industry    || data.kb_industry    || '';

const date = new Date().toLocaleDateString('en-IN', {
  year: 'numeric', month: 'long', day: 'numeric'
});

// Safe string converter
const safe = (val) => {
  if (val === null || val === undefined) return 'Not available';
  if (Array.isArray(val)) return val.join(', ');
  if (typeof val === 'object') return JSON.stringify(val);
  return String(val).replace(/\n/g, ' ');
};

// Parse || separated items into array
const parseItems = (text) => {
  if (!text || text === 'Not available') return [];
  return text.split('||').map(s => s.trim()).filter(Boolean);
};

// Parse root causes (CAUSE 1: title — desc || CAUSE 2...)
const renderRootCauses = (text) => {
  const items = parseItems(text);
  if (!items.length) return `<div class="section-box">${safe(text)}</div>`;

  const colors = ['#DC2626','#B45309','#1A3C6E'];
  const bgColors = ['#FEE2E2','#FEF3C7','#EEF4FB'];

  return items.map((item, i) => {
    const parts = item.split('—').map(s => s.trim());
    const title = parts[0].replace(/^CAUSE\s*\d+:\s*/i, '').trim();
    const desc  = parts[1] || '';
    const rest  = parts.slice(2).join('—').trim();
    return `
    <div style="display:flex;gap:14px;padding:14px 16px;background:${bgColors[i]||'#F5F5F5'};border-radius:8px;margin-bottom:10px;border:1px solid ${colors[i]||'#ccc'}20;">
      <div style="width:28px;height:28px;border-radius:50%;background:${colors[i]||'#888'};color:white;font-weight:700;font-size:12px;display:flex;align-items:center;justify-content:center;flex-shrink:0;">${i+1}</div>
      <div>
        <div style="font-weight:700;font-size:13px;color:#1A1A1A;margin-bottom:4px;">${title}</div>
        ${desc ? `<div style="font-size:13px;color:#555;line-height:1.6;">${desc}</div>` : ''}
        ${rest ? `<div style="margin-top:6px;display:inline-block;padding:2px 10px;background:${colors[i]||'#888'}20;border-radius:4px;font-size:11px;font-weight:700;color:${colors[i]||'#888'};">${rest}</div>` : ''}
      </div>
    </div>`;
  }).join('');
};

// Parse phases (PHASE 1 (Wk X-X): what | Team: who | Outcome: result)
const renderPhases = (text) => {
  const items = parseItems(text);
  if (!items.length) return `<div class="section-box">${safe(text)}</div>`;

  const phColors = ['#1A3C6E','#E07B2A','#16A34A','#7C3AED'];

  return `
  <table style="width:100%;border-collapse:collapse;font-size:13px;">
    <thead>
      <tr>
        ${['Phase','Deliverables','Team','Timeline','Outcome'].map(h =>
          `<th style="background:#1A3C6E;color:white;padding:10px 12px;text-align:left;font-size:12px;">${h}</th>`
        ).join('')}
      </tr>
    </thead>
    <tbody>
      ${items.map((item, i) => {
        const phaseMatch = item.match(/PHASE\s*(\d+)[^:]*:\s*(.*?)(?=\|Team:|$)/i);
        const teamMatch  = item.match(/Team:\s*(.*?)(?=\|Outcome:|$)/i);
        const outcomeMatch = item.match(/Outcome:\s*(.*?)$/i);
        const weekMatch  = item.match(/\(Wk[s]?\s*([\d\-]+)\)/i);

        const phaseNum   = phaseMatch?.[1] || (i+1).toString();
        const phaseDesc  = phaseMatch?.[2]?.trim() || item;
        const team       = teamMatch?.[1]?.trim()  || 'Tiger Analytics Team';
        const outcome    = outcomeMatch?.[1]?.trim()|| '';
        const weeks      = weekMatch?.[1] ? `Wk ${weekMatch[1]}` : '';
        const bg         = i % 2 === 0 ? '#F8FAFC' : '#FFFFFF';

        return `
        <tr style="background:${bg};">
          <td style="padding:11px 12px;border-bottom:1px solid #E2E8F0;vertical-align:top;">
            <span style="width:24px;height:24px;border-radius:50%;background:${phColors[i]||'#888'};color:white;font-weight:700;font-size:11px;display:inline-flex;align-items:center;justify-content:center;margin-right:8px;">${phaseNum}</span>
          </td>
          <td style="padding:11px 12px;border-bottom:1px solid #E2E8F0;vertical-align:top;font-size:13px;">${phaseDesc}</td>
          <td style="padding:11px 12px;border-bottom:1px solid #E2E8F0;vertical-align:top;font-size:12px;color:#555;">${team}</td>
          <td style="padding:11px 12px;border-bottom:1px solid #E2E8F0;vertical-align:top;"><span style="background:#EEF4FB;color:#1A3C6E;padding:2px 8px;border-radius:4px;font-size:11px;font-weight:600;">${weeks}</span></td>
          <td style="padding:11px 12px;border-bottom:1px solid #E2E8F0;vertical-align:top;font-size:12px;color:#16A34A;font-weight:600;">${outcome}</td>
        </tr>`;
      }).join('')}
    </tbody>
  </table>`;
};

// Parse pain solution map
const renderPainMap = (text) => {
  const items = parseItems(text);
  if (!items.length) return `<div class="section-box">${safe(text)}</div>`;

  const sevColors = { critical:'#DC2626', high:'#B45309', medium:'#1A3C6E' };
  const sevBg     = { critical:'#FEE2E2', high:'#FEF3C7', medium:'#EEF4FB' };

  return `
  <table style="width:100%;border-collapse:collapse;font-size:13px;">
    <thead>
      <tr>
        ${['Pain Point','Severity','Solution','Outcome','By'].map(h =>
          `<th style="background:#1A3C6E;color:white;padding:10px 12px;text-align:left;font-size:12px;">${h}</th>`
        ).join('')}
      </tr>
    </thead>
    <tbody>
      ${items.map((item, i) => {
        const painMatch     = item.match(/PAIN:\s*(.*?)(?=\|SEVERITY:|$)/i);
        const sevMatch      = item.match(/SEVERITY:\s*(.*?)(?=\|ROOT CAUSE:|$)/i);
        const solMatch      = item.match(/SOLUTION:\s*(.*?)(?=\|OUTCOME:|$)/i);
        const outcomeMatch  = item.match(/OUTCOME:\s*(.*?)(?=\|BY:|$)/i);
        const byMatch       = item.match(/BY:\s*(.*?)$/i);

        const pain    = painMatch?.[1]?.trim()    || item;
        const sev     = (sevMatch?.[1]?.trim()    || 'High').toLowerCase();
        const sol     = solMatch?.[1]?.trim()     || '';
        const outcome = outcomeMatch?.[1]?.trim() || '';
        const by      = byMatch?.[1]?.trim()      || '';
        const bg      = i % 2 === 0 ? '#F8FAFC' : '#FFFFFF';
        const color   = sevColors[sev] || sevColors.high;
        const bgSev   = sevBg[sev]    || sevBg.high;

        return `
        <tr style="background:${bg};">
          <td style="padding:10px 12px;border-bottom:1px solid #E2E8F0;vertical-align:top;font-size:13px;">
            <span style="display:inline-block;padding:2px 7px;border-radius:4px;font-size:10px;font-weight:700;background:${bgSev};color:${color};margin-bottom:4px;">${sev.toUpperCase()}</span><br>${pain}
          </td>
          <td style="padding:10px 12px;border-bottom:1px solid #E2E8F0;vertical-align:top;"><span style="padding:3px 9px;border-radius:4px;background:${bgSev};color:${color};font-size:11px;font-weight:700;">${sev.charAt(0).toUpperCase()+sev.slice(1)}</span></td>
          <td style="padding:10px 12px;border-bottom:1px solid #E2E8F0;vertical-align:top;font-size:13px;">${sol}</td>
          <td style="padding:10px 12px;border-bottom:1px solid #E2E8F0;vertical-align:top;font-size:12px;color:#16A34A;font-weight:600;">${outcome}</td>
          <td style="padding:10px 12px;border-bottom:1px solid #E2E8F0;vertical-align:top;"><span style="background:#EEF4FB;color:#1A3C6E;padding:2px 8px;border-radius:4px;font-size:11px;font-weight:600;">${by}</span></td>
        </tr>`;
      }).join('')}
    </tbody>
  </table>`;
};

// Parse accelerators
const renderAccelerators = (text) => {
  const items = parseItems(text);
  if (!items.length) return `<div class="section-box">${safe(text)}</div>`;

  return `<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:12px;">
    ${items.map(item => {
      const nameMatch  = item.match(/NAME:\s*(.*?)(?=\|WHAT:|$)/i);
      const whatMatch  = item.match(/WHAT:\s*(.*?)(?=\|SAVES:|$)/i);
      const savesMatch = item.match(/SAVES:\s*(.*?)$/i);
      const name  = nameMatch?.[1]?.trim()  || item;
      const what  = whatMatch?.[1]?.trim()  || '';
      const saves = savesMatch?.[1]?.trim() || '';
      return `
      <div style="border:1.5px solid #E2E8F0;border-radius:10px;padding:14px;">
        <div style="font-weight:700;font-size:13px;color:#1A3C6E;margin-bottom:6px;">⚡ ${name}</div>
        <div style="font-size:12px;color:#555;line-height:1.5;margin-bottom:8px;">${what}</div>
        ${saves ? `<span style="background:#DCFCE7;color:#16A34A;padding:3px 10px;border-radius:20px;font-size:11px;font-weight:700;">Saves ${saves}</span>` : ''}
      </div>`;
    }).join('')}
  </div>`;
};

// Parse investment ROI
const renderROI = (text) => {
  if (!text || text === 'Not available') return `<div class="section-box">${safe(text)}</div>`;

  const parts = text.split('||').map(s => s.trim());
  const phasePart = parts[0] || '';
  const roiPart   = parts[1] || '';

  const phaseRows = phasePart.split('|').map(s => s.trim()).filter(Boolean);
  const roiItems  = roiPart.split('|').map(s => s.trim()).filter(Boolean);

  return `
  <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;">
    <div>
      <div style="font-size:12px;font-weight:700;color:#1A3C6E;margin-bottom:10px;text-transform:uppercase;letter-spacing:.5px;">Phase Investment</div>
      <table style="width:100%;border-collapse:collapse;font-size:13px;">
        ${phaseRows.map((row, i) => {
          const [label, val] = row.split(':').map(s => s.trim());
          const isTotal = label?.toLowerCase().includes('total');
          return `<tr style="background:${isTotal ? '#EEF4FB' : i%2===0?'#F8FAFC':'#FFF'};">
            <td style="padding:9px 12px;border-bottom:1px solid #E2E8F0;${isTotal?'font-weight:700;color:#1A3C6E;':''}">${label||''}</td>
            <td style="padding:9px 12px;border-bottom:1px solid #E2E8F0;text-align:right;font-weight:700;${isTotal?'color:#1A3C6E;':''}">${val||''}</td>
          </tr>`;
        }).join('')}
      </table>
    </div>
    <div>
      <div style="font-size:12px;font-weight:700;color:#1A3C6E;margin-bottom:10px;text-transform:uppercase;letter-spacing:.5px;">Return on Investment</div>
      ${roiItems.map(item => {
        const [label, val] = item.split(':').map(s => s.trim());
        const isPayback = label?.toLowerCase().includes('payback');
        const isRisk    = label?.toLowerCase().includes('risk') || label?.toLowerCase().includes('loss');
        const isROI     = label?.toLowerCase().includes('roi');
        const bg    = isPayback ? '#1A3C6E' : isRisk ? '#FEE2E2' : '#DCFCE7';
        const color = isPayback ? 'white'   : isRisk ? '#DC2626' : '#16A34A';
        const textColor = isPayback ? 'rgba(255,255,255,.8)' : '#555';
        return `
        <div style="display:flex;justify-content:space-between;align-items:center;padding:9px 14px;border-radius:7px;background:${bg};margin-bottom:6px;">
          <span style="font-size:13px;color:${textColor};">${label||''}</span>
          <span style="font-weight:700;font-size:14px;color:${color};">${val||''}</span>
        </div>`;
      }).join('')}
    </div>
  </div>`;
};

// Parse risk mitigation
const renderRisks = (text) => {
  const items = parseItems(text);
  if (!items.length) return `<div class="section-box">${safe(text)}</div>`;

  const likColors = { high:'#DC2626', medium:'#B45309', low:'#16A34A' };
  const likBg     = { high:'#FEE2E2', medium:'#FEF3C7', low:'#DCFCE7' };

  return `
  <table style="width:100%;border-collapse:collapse;font-size:13px;">
    <thead>
      <tr>
        ${['Risk','Likelihood','Tiger Mitigation','Protection'].map(h =>
          `<th style="background:#F8FAFC;color:#1A1A1A;padding:10px 12px;text-align:left;font-size:12px;font-weight:700;border-bottom:2px solid #E2E8F0;">${h}</th>`
        ).join('')}
      </tr>
    </thead>
    <tbody>
      ${items.map((item, i) => {
        const riskMatch  = item.match(/RISK:\s*(.*?)(?=\|LIKELIHOOD:|$)/i);
        const likeMatch  = item.match(/LIKELIHOOD:\s*(.*?)(?=\|MITIGATION:|$)/i);
        const mitMatch   = item.match(/MITIGATION:\s*(.*?)(?=\|PROTECTION:|$)/i);
        const protMatch  = item.match(/PROTECTION:\s*(.*?)$/i);

        const risk  = riskMatch?.[1]?.trim()  || item;
        const like  = (likeMatch?.[1]?.trim() || 'Medium').toLowerCase();
        const mit   = mitMatch?.[1]?.trim()   || '';
        const prot  = protMatch?.[1]?.trim()  || '';
        const color = likColors[like] || likColors.medium;
        const bg    = likBg[like]    || likBg.medium;
        const rowBg = i % 2 === 0 ? '#F8FAFC' : '#FFFFFF';

        return `
        <tr style="background:${rowBg};">
          <td style="padding:10px 12px;border-bottom:1px solid #E2E8F0;font-weight:600;vertical-align:top;">${risk}</td>
          <td style="padding:10px 12px;border-bottom:1px solid #E2E8F0;vertical-align:top;"><span style="padding:3px 9px;border-radius:4px;background:${bg};color:${color};font-size:11px;font-weight:700;">${like.charAt(0).toUpperCase()+like.slice(1)}</span></td>
          <td style="padding:10px 12px;border-bottom:1px solid #E2E8F0;vertical-align:top;font-size:13px;color:#555;">${mit}</td>
          <td style="padding:10px 12px;border-bottom:1px solid #E2E8F0;vertical-align:top;font-size:12px;color:#16A34A;font-weight:600;">${prot}</td>
        </tr>`;
      }).join('')}
    </tbody>
  </table>`;
};

// Parse team
const renderTeam = (text) => {
  const items = parseItems(text);
  if (!items.length) return `<div class="section-box">${safe(text)}</div>`;

  const avatarColors = ['#1A3C6E','#E07B2A','#16A34A','#7C3AED'];

  return `<div style="display:grid;grid-template-columns:repeat(4,1fr);gap:12px;">
    ${items.map((item, i) => {
      const roleMatch  = item.match(/ROLE:\s*(.*?)(?=\|EXP:|$)/i);
      const expMatch   = item.match(/EXP:\s*(.*?)(?=\|SKILL:|$)/i);
      const skillMatch = item.match(/SKILL:\s*(.*?)$/i);
      const role  = roleMatch?.[1]?.trim()  || item;
      const exp   = expMatch?.[1]?.trim()   || '';
      const skill = skillMatch?.[1]?.trim() || '';
      const initials = role.split(' ').map(w=>w[0]).join('').substring(0,2).toUpperCase();
      const color = avatarColors[i] || '#1A3C6E';
      return `
      <div style="border:1px solid #E2E8F0;border-radius:10px;padding:14px;text-align:center;">
        <div style="width:44px;height:44px;border-radius:50%;background:${color};color:white;font-weight:700;font-size:14px;display:flex;align-items:center;justify-content:center;margin:0 auto 10px;">${initials}</div>
        <div style="font-weight:700;font-size:12px;color:#1A3C6E;margin-bottom:4px;">${role}</div>
        <div style="font-size:11px;color:#555;margin-bottom:8px;line-height:1.4;">${exp}</div>
        ${skill ? `<span style="background:#EEF4FB;color:#1A3C6E;padding:2px 8px;border-radius:4px;font-size:10px;font-weight:600;">${skill}</span>` : ''}
      </div>`;
    }).join('')}
  </div>`;
};

// Parse credentials
const renderCredentials = (text) => {
  const items = parseItems(text);
  if (!items.length) return `<div class="section-box">${safe(text)}</div>`;

  const credColors = ['#FEF3C7','#EEF4FB','#EDE9FE','#DCFCE7'];
  const credIcons  = ['🏆','☁️','📊','🌏'];

  return `<div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;">
    ${items.map((item, i) => {
      const awardMatch = item.match(/(?:AWARD|CREDENTIAL):\s*(.*?)(?=\|RELEVANCE:|$)/i);
      const relMatch   = item.match(/RELEVANCE:\s*(.*?)$/i);
      const award = awardMatch?.[1]?.trim() || item;
      const rel   = relMatch?.[1]?.trim()   || '';
      return `
      <div style="background:${credColors[i]||'#F5F5F5'};border-radius:9px;padding:14px;">
        <div style="font-size:20px;margin-bottom:6px;">${credIcons[i]||'⭐'}</div>
        <div style="font-weight:700;font-size:13px;margin-bottom:4px;">${award}</div>
        <div style="font-size:12px;color:#555;line-height:1.4;">${rel}</div>
      </div>`;
    }).join('')}
  </div>`;
};

// Parse next steps timeline
const renderNextSteps = (text) => {
  const items = parseItems(text);
  if (!items.length) return `<div class="section-box">${safe(text)}</div>`;

  return `<div style="display:flex;flex-direction:column;gap:0;">
    ${items.map((item, i) => {
      const whenMatch  = item.match(/WHEN:\s*(.*?)(?=\|(?:TITLE|ACTION):|$)/i);
