const data = $input.first().json;

const text =
  JSON.stringify(data).toLowerCase();

const blockedPatterns = [

  'ignore previous instructions',

  'system prompt',

  'developer mode',

  'jailbreak',

  'reveal prompt',

  'bypass security',

  'act as',

  'pretend to be',

  'show hidden instructions',

  'ignore all previous'

];

const detected =
  blockedPatterns.find(p =>
    text.includes(p)
  );

if (detected) {

  throw new Error(
    `Unsafe prompt detected: ${detected}`
  );

}

return [
  {
    json: data
  }
];

let proposal = {};
const prev = $input.first().json;

try {
  let rawText = $input.first().json
    ?.content?.[0]?.text || '';

  if (!rawText) throw new Error('Empty text');

  // Remove control characters
  rawText = rawText
    .replace(/[\u0000-\u001F\u007F-\u009F]/g, ' ')
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();

  const firstBrace = rawText.indexOf('{');
  const lastBrace = rawText.lastIndexOf('}');

  if (firstBrace === -1 || lastBrace === -1) {
    throw new Error('No JSON found');
  }

  const parsed = JSON.parse(
    rawText.substring(firstBrace, lastBrace + 1)
  );

  proposal = {
    engagement_title:      parsed.engagement_title      || 'AI-Powered Analytics Program',
    situation_assessment:  parsed.situation_assessment  || 'Not available',
    root_cause_diagnosis:  parsed.root_cause_diagnosis  || 'Not available',
    tiger_pov:             parsed.tiger_pov             || 'Not available',
    proposed_solution:     parsed.proposed_solution     || 'Not available',
    pain_solution_map:     parsed.pain_solution_map     || 'Not available',
    tiger_accelerators:    parsed.tiger_accelerators    || 'Not available',
    investment_roi:        parsed.investment_roi        || 'Not available',
    risk_mitigation:       parsed.risk_mitigation       || 'Not available',
    our_team:              parsed.our_team              || 'Not available',
    credentials:           parsed.credentials           || 'Not available',
    next_steps:            parsed.next_steps            || 'Not available',
  };

} catch (e) {

  // Regex fallback — extract each field
  const rawText = $input.first().json
    ?.content?.[0]?.text || '';

  const extract = (key) => {
    const keyIndex = rawText.indexOf(`"${key}"`);
    if (keyIndex === -1) return 'Not available';
    const colonIndex = rawText.indexOf(':', keyIndex);
    if (colonIndex === -1) return 'Not available';
    const openQuote = rawText.indexOf('"', colonIndex);
    if (openQuote === -1) return 'Not available';
    let i = openQuote + 1;
    let value = '';
    while (i < rawText.length) {
      const char = rawText[i];
      if (char === '\\') {
        i++;
        const e = rawText[i];
        if (e === 'n') value += ' ';
        else if (e === '"') value += '"';
        else if (e === '\\') value += '\\';
        else value += e;
      } else if (char === '"') {
        break;
      } else {
        value += char;
      }
      i++;
    }
    return value.trim() || 'Not available';
  };

  proposal = {
    engagement_title:      extract('engagement_title') || 'AI-Powered Analytics Program',
    situation_assessment:  extract('situation_assessment'),
    root_cause_diagnosis:  extract('root_cause_diagnosis'),
    tiger_pov:             extract('tiger_pov'),
    proposed_solution:     extract('proposed_solution'),
    pain_solution_map:     extract('pain_solution_map'),
    tiger_accelerators:    extract('tiger_accelerators'),
    investment_roi:        extract('investment_roi'),
    risk_mitigation:       extract('risk_mitigation'),
    our_team:              extract('our_team'),
    credentials:           extract('credentials'),
    next_steps:            extract('next_steps'),
  };
}

return {
  ...prev,
  proposal: proposal,
  generated_at: new Date().toISOString(),
  retry_count: prev.retry_count || 0
};
